+                const decimal_pos = coeff.len - neg_exp;
+                try result.appendSlice(coeff[0..decimal_pos]);
+                try result.append('.');
+                try result.appendSlice(coeff[decimal_pos..]);
+            }
+        }
+
+        return result.toOwnedSlice();
+    }
